export interface User {
  id: number;
  name: string;
  email: string;
  phone?: string;
  website?: string;
  company?: { name: string };
}

// Route params — always strings from URL
export type UserRouteParams = {
  userId: string;
};

const { userId } = useParams<UserRouteParams>();

useEffect(() => {
  if (!userId || isNaN(Number(userId))) {
    setNotFound(true);
    return;
  }
  fetchUser(Number(userId)).then(setUser).catch(handleError);
}, [userId]);

